// =============================================================================
// REVENANT - Cloud-Native Drift Analyzer
// Pure JS translation of the Python Data Science engine for n8n Cloud
// =============================================================================

// Hard-coded baseline statistics (from training / earlier dataset)
const BASELINE = {
    transaction_amount_mean: 2500000.0,
    transaction_amount_std: 5000000.0,
    risk_score_mean: 45.0,
    risk_score_std: 25.0,
};

const DRIFT_Z_THRESHOLD = 2.0;

// 1. Ingest Data from the previous node
const items = $input.all().map(item => item.json);

if (items.length === 0) {
    return [{ json: { status: "Skipped", reason: "No data in the last 7 days." } }];
}

const n = items.length;

// =============================================================================
// A. Confidence Degradation (Linear Regression: y = mx + b)
// =============================================================================
let sumX = 0, sumY = 0, sumXY = 0, sumX2 = 0;
items.forEach((row, i) => {
    const y = parseFloat(row.model_confidence) || 0;
    sumX += i;
    sumY += y;
    sumXY += (i * y);
    sumX2 += (i * i);
});

let slope = 0;
if (n > 1) {
    slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
}
const avgConfidence = sumY / n;

// =============================================================================
// B. Feature Drift (Z-Score Analysis on Escalated Tickets)
// =============================================================================
const escalated = items.filter(r => r.consensus_action === 'ESCALATE');
const drift = { transaction_amount: { drifted: false }, risk_score: { drifted: false } };

if (escalated.length > 5) {
    // Transaction Amount Z-Score
    const amtMean = escalated.reduce((acc, r) => acc + (parseFloat(r.transaction_amount) || 0), 0) / escalated.length;
    const zAmt = (amtMean - BASELINE.transaction_amount_mean) / BASELINE.transaction_amount_std;
    drift.transaction_amount = {
        current_mean: Number(amtMean.toFixed(2)),
        z_score: Number(zAmt.toFixed(4)),
        drifted: Math.abs(zAmt) > DRIFT_Z_THRESHOLD
    };

    // Risk Score Z-Score
    const riskMean = escalated.reduce((acc, r) => acc + (parseFloat(r.risk_score) || 0), 0) / escalated.length;
    const zRisk = (riskMean - BASELINE.risk_score_mean) / BASELINE.risk_score_std;
    drift.risk_score = {
        current_mean: Number(riskMean.toFixed(2)),
        z_score: Number(zRisk.toFixed(4)),
        drifted: Math.abs(zRisk) > DRIFT_Z_THRESHOLD
    };
} else {
    drift.transaction_amount.note = "insufficient data";
    drift.risk_score.note = "insufficient data";
}

// =============================================================================
// C. False Positive Analysis
// =============================================================================
const denied = items.filter(r => r.consensus_action === 'DENY');
const falsePositives = denied.filter(r => 
    r.human_override === true || String(r.human_override).toLowerCase() === 'true'
);

const fpRate = denied.length > 0 ? (falsePositives.length / denied.length) : 0;

// =============================================================================
// D. Final Recommendation Engine
// =============================================================================
const anyDrift = drift.transaction_amount.drifted || drift.risk_score.drifted;
const updateRecommendation = anyDrift || fpRate > 0.1;

// Output the final JSON Payload
return [{
    json: {
        report_type: "Weekly Delta Report",
        dataset_rows: n,
        confidence_trend: {
            slope: Number(slope.toFixed(6)),
            average: Number(avgConfidence.toFixed(4))
        },
        feature_drift: drift,
        false_positives: {
            count: falsePositives.length,
            total_deny: denied.length,
            rate: Number(fpRate.toFixed(4))
        },
        recommendation: updateRecommendation ? "UPDATE_RISK_WEIGHTS" : "WEIGHTS_STABLE"
    }
}];
